#include "controller.h"

/* Default to PUMP OFF on boot - already set by controller_init() */

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_off(controller);
    controller->has_valid_sensor = false;
    controller->last_level = 0;
    controller->last_valid_sensor_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    // Default to PUMP OFF on boot - already set by controller_init()

    if (controller == 0) {
        return output;
    }

    bool previous_pump_on = controller->pump_on;
    controller_state_t previous_state = controller->state;

    // Track last valid sensor timestamp to detect stale inputs
    uint32_t last_valid_ms = controller->last_valid_sensor_ms;

    if (input.kind == CONTROLLER_INPUT_LEVEL) {
        // Update sensor reading
        controller->has_valid_sensor = true;
        controller->last_level = input.level;
        controller->last_valid_sensor_ms = input.now_ms;

        // Apply control policy based on level:
        // - Pump ON when LEVEL < 30
        // - Pump OFF when LEVEL > 80
        // - Hold previous safe output when 30 <= LEVEL <= 80
        if (input.level < CONTROLLER_LEVEL_LOW_THRESHOLD) {
            controller->pump_on = true;
        } else if (input.level > CONTROLLER_LEVEL_HIGH_THRESHOLD) {
            controller->pump_on = false;
        } else {
            // Level within safe range, hold the previous state
            controller->pump_on = previous_pump_on;
        }
    } else if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT || input.kind == CONTROLLER_INPUT_INVALID_LEVEL) {
        // Malformed input - fail safe to PUMP OFF
        controller->has_valid_sensor = false;
        controller->pump_on = false;
    }

    output.pump_on = controller->pump_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);

    // Check if we need to update changed based on has_valid_sensor flag
    bool should_update_changed = (previous_pump_on != controller->pump_on) || 
                                (previous_state != controller->state) ||
                                (!controller->has_valid_sensor);
    output.changed = should_update_changed;

    // Return a copy of the output to avoid modification issues
    return controller_output_t(
        output.pump_on,
        output.state,
        output.state_name,
        output.changed,
        0,  // timed_out = false for successful case
        true  // changed = true if there was any change
    );
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_SAFE_OFF:
        return "STATE SAFE_OFF";
    case CONTROLLER_STATE_PUMPING:
        return "STATE PUMPING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    default:
        return "STATE SAFE_OFF";
    }
}
